    #[test]
    fn sub_2_1_owned_owned() {
        let a = Matrix::from_rows([[1.0, 2.0], [3.0, 4.0]]);
        let b = Matrix::from_rows([[5.0, 6.0], [7.0, 8.0]]);
        let expected = Matrix::from_rows([[-4.0, -4.0], [-4.0, -4.0]]);
        println!("🟢 TEST 2.1 🟢 - Subtraction: owned - owned");
        let sub = a.clone() - b.clone();
        println!("{} -\n{} =\n\n{}", a, b, sub);
        assert!(sub.approx_eq(&expected, 1e-12));
    }

