    #[test]
    fn add_3_commutative_on_known_pair() {
        let a = Matrix::from_rows([[1.0, 2.0], [3.0, 4.0]]);
        let b = Matrix::from_rows([[5.0, 6.0], [7.0, 8.0]]);
        println!("🟢 TEST 3 🟢 - Addition commutativity");
        let sum_ab = &a + &b;
        let sum_ba = &b + &a;
        println!("a + b =\n{}", sum_ab);
        println!("b + a =\n{}", sum_ba);
        assert!(sum_ab.approx_eq(&sum_ba, 1e-12));
    }

    // ── matmul ──

    #[test]
    fn matmul_4_1_owned_owned() {
        let a = Matrix::from_rows([[-1.2, 3.4], [8.9, -9.1]]);
        let b = Matrix::from_rows([[5.6, -6.7], [-2.0, 7.4]]);
        let expected = Matrix::from_rows([[-13.52, 33.20], [68.04, -126.97]]);
        println!("🟢 TEST 4.1 🟢 - Multiplication: owned * owned");
        let product = a.clone() * b.clone();
        println!("{} *\n{} =\n\n{}", a, b, product);
        assert!(product.approx_eq(&expected, 1e-10));
    }

